package org.blogs.Blogs.service;import lombok.Getter;import org.blogs.Blogs.entity.UserEntity;import org.springframework.security.core.GrantedAuthority;import org.springframework.security.core.userdetails.UserDetails;import java.util.Collection;import java.util.List;@Getterpublic class CustomUserDetails implements UserDetails {    private final UserEntity user;    public CustomUserDetails(UserEntity user) {        this.user = user;    }    @Override    public String getUsername() {        return user.getEmail();    }    @Override    public String getPassword() {        return user.getPassword();    }    @Override    public Collection<? extends GrantedAuthority> getAuthorities() {        return List.of();    }}